from pydantic import BaseModel, field_validator

class User(BaseModel):
    username: str

    @field_validator('username')
    @classmethod
    def no_spaces(cls, v: str) -> str:
        if ' ' in v:
            raise ValueError('username cannot contain spaces')
        return v.lower()
